// Validator — pure schema check. Never throws.
const webhookData = $('Webhook').first().json;
const payload = webhookData.body || webhookData;
const config = $('Config').first().json.config;

function checkSchema(p) {
  if (!p || typeof p !== 'object') return 'payload is not an object';
  const topKeys = ['call_id','caller_phone','started_at','ended_at','intake','qualification','audio_url','transcript'];
  for (const k of topKeys) if (!(k in p)) return `missing top-level key: ${k}`;
  if (typeof p.intake !== 'object' || p.intake === null) return 'intake must be an object';
  const intakeKeys = ['name','phone','incident_date','location','injury_description','age','death_involved'];
  for (const k of intakeKeys) if (!(k in p.intake)) return `missing intake.${k}`;
  if (typeof p.qualification !== 'object' || p.qualification === null) return 'qualification must be an object';
  const qualKeys = ['within_statute','at_fault','received_treatment','other_party_insured','caller_has_um_coverage','flags'];
  for (const k of qualKeys) if (!(k in p.qualification)) return `missing qualification.${k}`;
  if (typeof p.qualification.at_fault !== 'boolean') return 'qualification.at_fault must be boolean';
  if (typeof p.qualification.received_treatment !== 'boolean') return 'qualification.received_treatment must be boolean';
  if (typeof p.qualification.other_party_insured !== 'boolean') return 'qualification.other_party_insured must be boolean';
  if (!Array.isArray(p.qualification.flags)) return 'qualification.flags must be array';
  if (typeof p.intake.death_involved !== 'boolean') return 'intake.death_involved must be boolean';
  if (typeof p.intake.age !== 'number') return 'intake.age must be number';
  if (isNaN(Date.parse(p.intake.incident_date))) return 'intake.incident_date is not a valid date';
  return null;
}

const err = checkSchema(payload);
return [{ json: { valid: err === null, validation_error: err, payload: payload, config: config } }];

// Qualifier — MVA decision table.
const item = $input.first().json;
const { payload, config } = item;

const incidentDate = new Date(payload.intake.incident_date);
const cutoff = new Date();
cutoff.setFullYear(cutoff.getFullYear() - config.statute_years);
const within_statute = incidentDate >= cutoff;

const flags = payload.qualification.flags || [];
let route, reason, stage_id;

if (flags.length > 0) {
  route = 'human_review';
  reason = 'Flags: ' + flags.join(',');
  stage_id = config.stage_human_review;
} else {
  const otherInsured = payload.qualification.other_party_insured === true;
  const umCoverage = payload.qualification.caller_has_um_coverage === true;
  const insuranceGate = otherInsured || umCoverage;
  const gatesPass = within_statute && payload.qualification.at_fault === false && payload.qualification.received_treatment === true && insuranceGate;
  if (gatesPass) {
    route = 'qualified';
    reason = 'All 4 gates passed';
    stage_id = config.stage_qualified;
  } else {
    route = 'non_qualified';
    const failures = [];
    if (!within_statute) failures.push('outside_statute');
    if (payload.qualification.at_fault) failures.push('at_fault');
    if (!payload.qualification.received_treatment) failures.push('no_treatment');
    if (!insuranceGate) failures.push('no_insurance');
    reason = failures.join(',');
    stage_id = config.stage_non_qualified;
  }
}

return [{ json: { call_id: payload.call_id, caller_phone: payload.caller_phone, route, reason, hubspot_stage_id: stage_id, within_statute, phase: 'phase-1-stub' } }];
